diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 8b23583c5106..a0c9d068384b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7012,6 +7012,17 @@ CmpInst *InstCombinerImpl::canonicalizeICmpPredicate(CmpInst &I) {
   if (InstCombiner::isCanonicalPredicate(Pred))
     return nullptr;

+  // Avoid canonicalizing comparisons against zero that have select users,
+  // as the select operands may have conditional undefined behavior
+  // based on the zero check (e.g., cttz with is_zero_poison=false).
+  ConstantInt *C = dyn_cast<ConstantInt>(I.getOperand(1));
+  if (C && C->isZero()) {
+    for (User *U : I.users()) {
+      if (isa<SelectInst>(U))
+        return nullptr;
+    }
+  }
+
   // Can all users be adjusted to predicate inversion?
   if (!InstCombiner::canFreelyInvertAllUsersOf(&I, /*IgnoredUser=*/nullptr))
     return nullptr;
