diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index e7a8e947705f..16801614507c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -1221,12 +1221,10 @@ static Value *foldSelectCttzCtlz(ICmpInst *ICI, Value *TrueVal, Value *FalseVal,
     return SelectArg;
   }

-  // The ValueOnZero is not the bitwidth. But if the cttz/ctlz (and optional
-  // zext/trunc) have one use (ending at the select), the cttz/ctlz result will
-  // not be used if the input is zero. Relax to 'zero is poison' for that case.
-  if (II->hasOneUse() && SelectArg->hasOneUse() &&
-      !match(II->getArgOperand(1), m_One()))
-    II->setArgOperand(1, ConstantInt::getTrue(II->getContext()));
+  // The ValueOnZero is not the bitwidth, so we cannot safely change
+  // the 'is_zero_poison' flag. Both operands of a select are evaluated,
+  // so setting 'is_zero_poison' to true would introduce poison when
+  // the input is zero, causing undefined behavior.

   return nullptr;
 }
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index cdb2c11ef046..212b11e6e31a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -81,6 +81,32 @@
 using namespace llvm;
 using namespace PatternMatch;

+/// Check if the intrinsic has select users that might depend on the zero case.
+/// This is true if there's a select that uses the intrinsic result and also
+/// uses the input value in a comparison against zero.
+static bool hasSelectUserDependingOnZeroCase(IntrinsicInst &II) {
+  Value *Input = II.getArgOperand(0);
+  for (User *U : II.users()) {
+    SelectInst *SI = dyn_cast<SelectInst>(U);
+    if (!SI)
+      continue;
+    
+    // Check if the select condition compares the input against zero
+    Value *Cond = SI->getCondition();
+    ICmpInst *ICI = dyn_cast<ICmpInst>(Cond);
+    if (!ICI || !ICI->isEquality())
+      continue;
+    
+    Value *LHS = ICI->getOperand(0);
+    Value *RHS = ICI->getOperand(1);
+    if ((LHS == Input && match(RHS, m_Zero())) ||
+        (RHS == Input && match(LHS, m_Zero()))) {
+      return true;
+    }
+  }
+  return false;
+}
+
 STATISTIC(NumSimplified, "Number of library calls simplified");

 static cl::opt<unsigned> GuardWideningWindow(
@@ -605,11 +631,12 @@ static Instruction *foldCttzCtlz(IntrinsicInst &II, InstCombinerImpl &IC) {
     return IC.replaceInstUsesWith(II, C);
   }

-  // If the input to cttz/ctlz is known to be non-zero,
-  // then change the 'ZeroIsPoison' parameter to 'true'
-  // because we know the zero behavior can't affect the result.
-  if (!Known.One.isZero() ||
-      isKnownNonZero(Op0, IC.getSimplifyQuery().getWithInstruction(&II))) {
+  // If the input to cttz/ctlz is known to be non-zero and the intrinsic
+  // has no select users that might depend on the zero case, then change
+  // the 'ZeroIsPoison' parameter to 'true'.
+  if ((!Known.One.isZero() ||
+       isKnownNonZero(Op0, IC.getSimplifyQuery().getWithInstruction(&II))) &&
+      !hasSelectUserDependingOnZeroCase(II)) {
     if (!match(II.getArgOperand(1), m_One()))
       return IC.replaceOperand(II, 1, IC.Builder.getTrue());
   }
