diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 8b23583c5106..72e6246f3233 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7012,6 +7012,36 @@ CmpInst *InstCombinerImpl::canonicalizeICmpPredicate(CmpInst &I) {
   if (InstCombiner::isCanonicalPredicate(Pred))
     return nullptr;

+  // Avoid canonicalizing comparisons against zero that are used in selects
+  // where the other operand might be poison when the input is zero.
+  // This is particularly important for cttz/ctlz intrinsics with is_zero_poison=false.
+  ConstantInt *C = dyn_cast<ConstantInt>(I.getOperand(1));
+  if (C && C->isZero()) {
+    for (User *U : I.users()) {
+      if (isa<SelectInst>(U)) {
+        // Check if the select's other operand depends on a cttz/ctlz
+        // that would become poison if we canonicalize.
+        SelectInst *SI = cast<SelectInst>(U);
+        Value *TrueVal = SI->getTrueValue();
+        Value *FalseVal = SI->getFalseValue();
+        
+        auto isCttzCtlzWithZeroPoison = [](Value *V) {
+          if (auto *II = dyn_cast<IntrinsicInst>(V)) {
+            Intrinsic::ID ID = II->getIntrinsicID();
+            if ((ID == Intrinsic::cttz || ID == Intrinsic::ctlz) &&
+                match(II->getArgOperand(1), m_Zero())) {
+              return true;
+            }
+          }
+          return false;
+        };
+        
+        if (isCttzCtlzWithZeroPoison(TrueVal) || isCttzCtlzWithZeroPoison(FalseVal))
+          return nullptr;
+      }
+    }
+  }
+
   // Can all users be adjusted to predicate inversion?
   if (!InstCombiner::canFreelyInvertAllUsersOf(&I, /*IgnoredUser=*/nullptr))
     return nullptr;
